import sys

def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        n=int(next(it)); x=int(next(it))
        dp=[False]*(x+1)
        dp[0]=True
        for _ in range(n):
            a=int(next(it))
            for s in range(x, a-1, -1):
                if dp[s-a]:
                    dp[s]=True
        out.append('YES' if dp[x] else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

